/**
 * DOC-FLOW: Enviar WhatsApp
 * O que faz: Converte msg.reply no payload da API do WhatsApp.
 * Para que serve: Padronizar envio de texto, bot?es e listas.
 */
try {
  if (!msg || typeof msg !== 'object') return null;
  if (!msg.phone || typeof msg.phone !== 'string') return null;
  if (!msg.reply || typeof msg.reply !== 'object') return null;

  const reply = msg.reply || {};
  const replyType = String(reply.type || '').toLowerCase();

  const ctxCfg = (msg.ctx && typeof msg.ctx === 'object' && msg.ctx.configuracoes && typeof msg.ctx.configuracoes === 'object' && msg.ctx.configuracoes.waConfig && typeof msg.ctx.configuracoes.waConfig === 'object')
    ? msg.ctx.configuracoes.waConfig
    : {};
  const cfg = (msg.waConfig && typeof msg.waConfig === 'object') ? msg.waConfig : ctxCfg;

  const TOKEN = cfg && cfg.accessToken ? String(cfg.accessToken).trim() : '';
  const PHONE_ID = cfg && cfg.phoneNumberId ? String(cfg.phoneNumberId).trim() : (msg.phoneNumberId ? String(msg.phoneNumberId).trim() : '');

  if (!TOKEN || !PHONE_ID) {
    node.warn('Configura\u00e7\u00e3o WhatsApp ausente para envio (ACCESS_TOKEN/PHONE_NUMBER_ID).');
    return null;
  }

  msg.headers = { Authorization: 'Bearer ' + TOKEN, 'Content-Type': 'application/json' };
  msg.url = 'https://graph.facebook.com/v24.0/' + PHONE_ID + '/messages';
  msg.method = 'POST';

  const payload = {
    messaging_product: 'whatsapp',
    recipient_type: 'individual',
    to: msg.phone
  };

  if (replyType === 'interactive') {
    const rawButtons = Array.isArray(reply.buttons) ? reply.buttons : [];
    const buttons = [];
    for (const b of rawButtons) {
      if (!b || typeof b !== 'object') continue;
      if (b.id === undefined || b.title === undefined) continue;
      buttons.push({
        type: 'reply',
        reply: { id: String(b.id), title: String(b.title).substring(0, 20) }
      });
      if (buttons.length >= 3) break;
    }

    if (buttons.length === 0) {
      payload.type = 'text';
      payload.text = { body: String(reply.text || ''), preview_url: false };
    } else {
      payload.type = 'interactive';
      payload.interactive = {
        type: 'button',
        body: { text: String(reply.text || '') },
        action: { buttons }
      };
    }
  } else if (replyType === 'list') {
    const sectionsIn = Array.isArray(reply.sections) ? reply.sections : [];
    const sections = [];

    for (const s of sectionsIn) {
      if (!s || typeof s !== 'object') continue;
      const rowsIn = Array.isArray(s.rows) ? s.rows : [];
      const rows = [];

      for (const r of rowsIn) {
        if (!r || typeof r !== 'object') continue;
        if (r.id === undefined || r.title === undefined) continue;
        const row = {
          id: String(r.id),
          title: String(r.title).substring(0, 24)
        };
        if (r.description !== undefined && r.description !== null) {
          row.description = String(r.description).substring(0, 72);
        }
        rows.push(row);
      }

      if (rows.length > 0) {
        sections.push({
          title: String(s.title || 'Opções'),
          rows
        });
      }
    }

    if (sections.length === 0) {
      payload.type = 'text';
      payload.text = { body: String(reply.text || ''), preview_url: false };
    } else {
      payload.type = 'interactive';
      payload.interactive = {
        type: 'list',
        body: { text: String(reply.text || '') },
        action: {
          button: String(reply.buttonText || 'Ver opções').substring(0, 20),
          sections
        }
      };
    }
  } else {
    payload.type = 'text';
    payload.text = { body: String(reply.text || ''), preview_url: false };
  }

  msg.payload = payload;

  const buttonId = (msg.button === undefined || msg.button === null) ? '' : String(msg.button).trim();
  const shouldDestroyContext = !!msg.commandExit || ['MENU_SAIR', 'POS_SAIR', 'MEU_ACAO_SAIR'].includes(buttonId);
  if (shouldDestroyContext && msg.contextKey) {
    flow.set(msg.contextKey, null);
  }

  return msg;
} catch (e) {
  node.error('Erro em Enviar WhatsApp: ' + (e && e.message ? e.message : e), msg);
  return null;
}

