 if (query.length < 2) {
  msg.reply = { type: 'text', text: ' Digite pelo menos *2 letras* para buscar a especialidade.\n\nExemplo: *cardio*' };
  return msg;
 }

 const todas = Array.isArray(ctx.especialidades.todasEspecialidades) ? ctx.especialidades.todasEspecialidades : [];
 if (ctx.especialidades.especialidadeListaEmTela === true) {
  msg.reply = { type: 'text', text: ' Por favor, escolha uma op\u00e7\u00e3o da lista.' };
  return msg;
 }
 if (!todas || todas.length === 0) {
  ctx.especialidades.especialidadeBuscaPendente = raw;
  ctx.especialidades.especialidadeBuscaAtiva = true;
  ctx.especialidades.especialidadeListaEmTela = false;
  flow.set(contextKey, ctx);
  msg.buscarEspecialidades = true;
  msg.buscarEspecialidadesApi = true;
  return msg;
 }

 const resultados = todas.filter(e => normalize(e.nome || '').includes(query));
 if (resultados.length === 0) {
  msg.reply = { type: 'text', text: ' A especialidade informada não foi encontrada. Revise o nome digitado e tente novamente.' };
