 }

 const exibidos = resultados.slice(0, 10);
 msg.reply = {
  type: 'list',
  text: '*Resultados de Especialidades*\n\nBusca: *' + raw + '*\nEncontrados: *' + resultados.length + '*\n\nSelecione a especialidade na lista:' + (resultados.length > 10 ? '\n\n_Mostrando 10. Refine a busca para ver outras._' : ''),
  buttonText: 'Ver resultados',
  sections: [{ title: 'Especialidades', rows: exibidos.map(e => ({ id: 'ESP_' + e.codigo, title: (e.nome || '').length > 24 ? (e.nome || '').substring(0, 21) + '...' : (e.nome || '') })) }]
 };
 ctx.especialidades.especialidadeBuscaAtiva = true;
 ctx.especialidades.especialidadeListaEmTela = true;
 flow.set(contextKey, ctx);
 return msg;
}

if (!msg.button || !msg.button.startsWith('ESP_')) {
 msg.reply = { type: 'text', text: ' Por favor, escolha uma op\u00e7\u00e3o da lista.' };
 return msg;
}

const espCodigo = parseInt(msg.button.replace('ESP_', ''), 10);
const todasEspecialidades = Array.isArray(ctx.especialidades.todasEspecialidades) ? ctx.especialidades.todasEspecialidades : [];
const especialidade = todasEspecialidades.find(e => Number(e.codigo) === espCodigo);
if (!especialidade) {
 msg.reply = { type: 'text', text: ' Por favor, escolha uma op\u00e7\u00e3o da lista.' };
 return msg;
}

ctx.especialidades.especialidadeBuscaAtiva = false;
ctx.especialidades.especialidadeListaEmTela = false;
ctx.especialidades.especialidadeSelecionada = especialidade.codigo;
ctx.especialidades.especialidadeNome = especialidade.nome;
const establishmentIdAtual = Number(ctx.configuracoes.establishmentId || (ctx.configuracoes.waConfig && ctx.configuracoes.waConfig.establishmentId) || msg.establishmentId || 0);
const estInfo = await resolveEstabelecimento(establishmentIdAtual);
ctx.configuracoes.establishmentId = Number(establishmentIdAtual || 0);
ctx.configuracoes.estabelecimentoNome = estInfo.nome || '';
ctx.configuracoes.estabelecimentoEndereco = estInfo.endereco || '';
ctx.step = 'CONVENIO';
ctx.updatedAt = msg.now;
flow.set(contextKey, ctx);
msg.buscarConvenios = true;
return msg;
})();

/**
 * DOC-FLOW: Processar Convênios
 * O que faz: Recebe catelogo de convênios e prepara paginação/filtros.
 * Para que serve: Facilitar seleção de convenio pelo usuário.
 */
const ctx = msg.ctx;
const contextKey = msg.contextKey;
const response = msg.payload;

let convênios = [];

if (Array.isArray(response)) {
 convênios = response;
} else if (response && Array.isArray(response.results)) {
 convênios = response.results;
} else if (response.select && response.select[0] && response.select[0].resultSet) {
 convênios = response.select[0].resultSet;
}

const extractPlanosAtivos = (conv) => {
 const plans = Array.isArray(conv.plans) ? conv.plans : [];
 const ativos = plans.filter(p => (p.status || p.IE_ATIVO) === 'ACTIVE' || (p.status || p.IE_ATIVO) === 'A' || (p.active === true));

 const unicos = new Map();
 ativos.forEach(p => {
 const id = p.insurancePlanId || p.planId || p.id || p.INSURANCE_PLAN_ID;
 const nome = p.planDescription || p.description || p.name || p.PLAN_DESCRIPTION;
 const key = (id || '').toString();
 if (!key || !nome) return;
 if (!unicos.has(key)) unicos.set(key, { id: key, nome: nome.toString(), status: 'ACTIVE' });
 });

 return Array.from(unicos.values());
};

// Filtrar apenas convênios ativos
const convêniosAtivos = convênios.filter(c => {
 const status = c.active || c.IE_ATIVO || c.status;
 return status === 'ACTIVE' || status === 'A' || status === true;
});

// Agrupar por código para evitar duplicatas
const convêniosUnicos = new Map();
convêniosAtivos.forEach(conv => {
 const codeRaw = conv.insuranceId || conv.insuranceCode || conv.CD_CONVENIO || conv.code;
 const code = Number(codeRaw);
 const nome = conv.insuranceDescription || conv.DS_CONVENIO || conv.name;
 if (!Number.isFinite(code) || !nome) return;

 const planos = extractPlanosAtivos(conv);

 if (!convêniosUnicos.has(code)) {
 convêniosUnicos.set(code, { codigo: code, nome: nome.toString(), planos: planos });
 return;
 }

 const cur = convêniosUnicos.get(code);
 const mapPlan = new Map((cur.planos || []).map(p => [p.id.toString(), p]));
 planos.forEach(p => {
 if (!mapPlan.has(p.id.toString())) mapPlan.set(p.id.toString(), p);
 });
 cur.planos = Array.from(mapPlan.values());
 convêniosUnicos.set(code, cur);
});

let todosConvenios = Array.from(convêniosUnicos.values());

// SEPARAR PARTICULAR (51) dos demais
const particular = todosConvenios.find(c => c.codigo === 51);
const outrosConvenios = todosConvenios.filter(c => c.codigo !== 51);

if (particular) {
 todosConvenios = [particular, ...outrosConvenios.sort((a, b) => a.nome.localeCompare(b.nome))];
} else {
 todosConvenios = outrosConvenios.sort((a, b) => a.nome.localeCompare(b.nome));
}

if (todosConvenios.length === 0) {
 msg.reply = {
 type: 'text',
 text: ' Nenhum convenio disponivel no momento.\n\nTente novamente mais tarde.'
 };
 ctx.encerrado = true;
 flow.set(contextKey, ctx);
 return msg;
}

// Somente cacheia dados para busca por texto (evita montar lista redundante aqui)
ctx.convenioPlano.todosConvenios = todosConvenios;
ctx.convenioPlano.temMaisConvenios = false;
ctx.convenioPlano.temAnteriorConvenios = false;
ctx.convenioPlano.paginaConvenio = 0;
flow.set(contextKey, ctx);

return msg;

/**
 * DOC-FLOW: Convênio: Solicitar Busca
