 ctx: ctx
};

const buttons = [];

if (ctx.convenioPlano.temAnteriorConvenios) {
 buttons.push({ id: "CONV_ANTERIOR", title: " Anterior" });
}

if (ctx.convenioPlano.temMaisConvenios) {
 buttons.push({ id: "CONV_PROXIMO", title: "Proximo " });
}

let msgBotoes = null;

if (buttons.length > 0) {
