/**
 * DOC-FLOW: Processar Escolha Convenio
 */
const ctx = msg.ctx;
const contextKey = msg.contextKey;

if (!msg.button || !msg.button.startsWith('CONV_')) {
 const listaEmTela = !!(ctx && ctx.convenioPlano && ctx.convenioPlano.convenioListaEmTela);
 if (listaEmTela) {
  msg.reply = { type: 'text', text: ' Por favor, escolha uma op\u00e7\u00e3o da lista.' };
  return msg;
 }
 return null;
}

if (msg.button === 'CONV_PROXIMO' || msg.button === 'CONV_ANTERIOR') {
 const delta = msg.button === 'CONV_PROXIMO' ? 1 : -1;
 ctx.convenioPlano.paginaConvenio = Math.max(0, (ctx.convenioPlano.paginaConvenio || 0) + delta);
 ctx.updatedAt = msg.now;

 const todosConvenios = ctx.convenioPlano.todosConvenios || [];
 const paginaAtual = ctx.convenioPlano.paginaConvenio;
 const itensPorPagina = 10;
 const inicio = paginaAtual * itensPorPagina;
 const fim = inicio + itensPorPagina;
 const conveniosPagina = todosConvenios.slice(inicio, fim);
 const temMais = fim < todosConvenios.length;
 const temAnterior = paginaAtual > 0;

 msg.reply = {
  type: 'list',
  text: ' *Convenios Disponiveis*\n\n' + todosConvenios.length + ' convenios encontrados\nPagina ' + (paginaAtual + 1) + ' de ' + Math.ceil(todosConvenios.length / itensPorPagina) + '\n\nEscolha seu convenio:',
  buttonText: 'Ver convenios',
  sections: [{ title: 'Pagina ' + (paginaAtual + 1), rows: conveniosPagina.map(c => ({ id: 'CONV_' + c.codigo, title: c.nome.length > 24 ? c.nome.substring(0, 21) + '...' : c.nome })) }]
 };

 ctx.convenioPlano.temMaisConvenios = temMais;
 ctx.convenioPlano.temAnteriorConvenios = temAnterior;
 ctx.convenioPlano.convenioListaEmTela = true;
 flow.set(contextKey, ctx);
 msg.navegacao = true;
 msg.temNavegacaoConvenios = !!(temMais || temAnterior);
 return msg;
}

const convCodigo = parseInt(msg.button.replace('CONV_', ''), 10);
const todosConvenios = ctx.convenioPlano.todosConvenios || [];
const convenio = todosConvenios.find(c => c.codigo === convCodigo);

if (!convenio) {
 msg.reply = { type: 'text', text: ' Por favor, escolha uma op\u00e7\u00e3o da lista.' };
 return msg;
}

ctx.convenioPlano.convenioSelecionado = convenio.codigo;
ctx.convenioPlano.convenioNome = convenio.nome;
ctx.convenioPlano.paginaConvenio = 0;
ctx.convenioPlano.convenioListaEmTela = false;

const planos = Array.isArray(convenio.planos) ? convenio.planos : [];
if (!planos || planos.length === 0) {
 ctx.convenioPlano.planosDisponiveis = null;
 ctx.convenioPlano.planoSelecionado = null;
 ctx.convenioPlano.planoNome = null;
 ctx.convenioPlano.planoListaEmTela = false;
 ctx.step = 'CRIAR_AGENDA';
 ctx.updatedAt = msg.now;
 flow.set(contextKey, ctx);

 msg.naturalPersonCode = ctx.paciente.naturalPersonCode;
 msg.insuranceCode = convenio.codigo;
 if (ctx.modoExame) msg.internalProcedureCode = parseInt(ctx.exames.internalProcedureCode, 10);
 else msg.specialtyCode = ctx.especialidades.especialidadeSelecionada;
 msg.criarAgenda = true;
 return msg;
}

const planosAtivos = planos.filter(p => {
 const st = (p.status || p.IE_ATIVO || p.active);
 if (st === undefined || st === null) return true;
 return st === 'ACTIVE' || st === 'A' || st === true;
}).map(p => ({
 id: (p.id || p.insurancePlanId || p.planId || p.INSURANCE_PLAN_ID || '').toString(),
 nome: (p.nome || p.planDescription || p.description || p.name || p.PLAN_DESCRIPTION || '').toString()
})).filter(p => p.id && p.nome);

if (planosAtivos.length === 0) {
 ctx.convenioPlano.planosDisponiveis = null;
 ctx.convenioPlano.planoSelecionado = null;
 ctx.convenioPlano.planoNome = null;
 ctx.convenioPlano.planoListaEmTela = false;
 ctx.step = 'CRIAR_AGENDA';
 ctx.updatedAt = msg.now;
 flow.set(contextKey, ctx);

 msg.naturalPersonCode = ctx.paciente.naturalPersonCode;
 msg.insuranceCode = convenio.codigo;
 if (ctx.modoExame) msg.internalProcedureCode = parseInt(ctx.exames.internalProcedureCode, 10);
 else msg.specialtyCode = ctx.especialidades.especialidadeSelecionada;
 msg.criarAgenda = true;
 return msg;
}

ctx.convenioPlano.planosDisponiveis = planosAtivos;
ctx.convenioPlano.planoSelecionado = null;
ctx.convenioPlano.planoNome = null;
ctx.convenioPlano.planoListaEmTela = true;
ctx.step = 'PLANO';
ctx.updatedAt = msg.now;
flow.set(contextKey, ctx);

msg.reply = {
 type: 'list',
 text: ' *' + convenio.nome + '*\n\nAgora escolha o plano:' + (planosAtivos.length > 10 ? '\n\n_Mostrando 10. Se nao aparecer, procure outro convenio/plano._' : ''),
 buttonText: 'Ver planos',
 sections: [{ title: 'Planos', rows: planosAtivos.slice(0, 10).map(p => ({ id: 'PLAN_' + p.id, title: p.nome.length > 24 ? p.nome.substring(0, 21) + '...' : p.nome })) }]
};

return msg;

/**
 * DOC-FLOW: Montar Payload: Agenda Integrada
 * O que faz: Monta payload da criação de agenda integrada.
 * Para que serve: Enviar dados corretos para obter sugestões de horários.
 */
const ctx = msg.ctx || {};
const isExam = !!ctx.modoExame || !!msg.internalProcedureCode;
const plan = (msg.insurancePlanId || ctx.convenioPlano.planoSelecionado || '').toString();
const patientName = (msg.personName || ctx.paciente?.personName || '').toString();

let phone = msg.phone ? msg.phone.toString().replace(/D/g, '') : '';
if (phone.startsWith('55') && phone.length > 10) phone = phone.substring(2);

if (!msg.naturalPersonCode) {
  msg.reply = { type: 'text', text: ' Não consegui identificar o paciente para criar a agenda. Digite *menu* e tente novamente.' };
  return [null, msg];
}
if (!msg.insuranceCode) {
  msg.reply = { type: 'text', text: ' Não consegui identificar o convênio para criar a agenda. Digite *menu* e tente novamente.' };
  return [null, msg];
}

const body = {
  integratedSchedule: {
    establishmentId: Number(ctx.configuracoes?.establishmentId || msg.establishmentCode || 1),
    naturalPersonCode: msg.naturalPersonCode.toString(),
    insurance: { code: parseInt(msg.insuranceCode, 10) },
    username: 'chatbot_static'
  },
  items: []
};
if (plan) body.integratedSchedule.insurance.plan = plan;

if (isExam) {
  const internalProcedureCode = parseInt(msg.internalProcedureCode || ctx.exames?.internalProcedureCode, 10);
  if (!internalProcedureCode) {
    msg.reply = { type: 'text', text: ' Não consegui identificar o exame para criar a agenda. Digite *menu* e tente novamente.' };
    return [null, msg];
  }
  body.items.push({ duration: 30, schedulingType: 'EXAM', internalProcedureCode });
} else {
  const specialtyCode = parseInt(msg.specialtyCode || ctx.especialidades?.especialidadeSelecionada, 10);
  if (!specialtyCode) {
    msg.reply = { type: 'text', text: ' Não consegui identificar a especialidade para criar a agenda. Digite *menu* e tente novamente.' };
    return [null, msg];
  }
  body.integratedSchedule.patient = { name: patientName, phone };
  body.items.push({ duration: 30, schedulingType: 'CONSULTATION', specialtyCode });
}

msg.payload = body;
msg.headers = { 'Content-Type': 'application/json' };
return [msg, null];

/**
 * DOC-FLOW: Processar Agenda Criada
 * O que faz: Lê retorno da agenda integrada e prepara consulta de horários.
 * Para que serve: Encadear automaticamente para etapa de horários disponíveis.
 */
const ctx = msg.ctx || {};
const contextKey = msg.contextKey;

const parseMaybeJson = (v) => {
  if (typeof v !== 'string') return v;
  const t = v.trim();
  if (!t) return v;
  if ((t.startsWith('{') && t.endsWith('}')) || (t.startsWith('[') && t.endsWith(']'))) {
    try { return JSON.parse(t); } catch (e) { return v; }
  }
  return v;
};

const raw = parseMaybeJson(msg.payload);
const response = raw && typeof raw === 'object' && raw.data ? raw.data : raw;

if (msg.statusCode && (msg.statusCode < 200 || msg.statusCode >= 300)) {
  node.error('Erro HTTP ' + msg.statusCode + ' ao criar agenda', msg);
  return msg;
}

if (!response || (typeof response !== 'object' && !Array.isArray(response))) {
  node.error('Erro: Resposta vazia/inválida da API de criação de agenda', msg);
  return msg;
}

const extractScheduleId = (obj) => {
  if (!obj) return null;
  const candidates = [
    obj.newIntegratedScheduleId,
    obj.integratedScheduleId,
    obj.code,
    obj.id,
    obj.scheduleId,
    obj?.result?.newIntegratedScheduleId,
    obj?.result?.integratedScheduleId,
    obj?.result?.code,
    obj?.data?.newIntegratedScheduleId,
    obj?.data?.integratedScheduleId,
    obj?.data?.code
  ];
  for (const c of candidates) {
    const n = Number(c);
    if (Number.isFinite(n) && n > 0) return n;
  }
  return null;
};

const scheduleId = extractScheduleId(response);
if (!scheduleId) {
  node.error('Erro: Resposta inesperada da API de criação de agenda: ' + JSON.stringify(response), msg);
  return msg;
}

ctx.dataHora = ctx.dataHora || {};
ctx.configuracoes = ctx.configuracoes || {};
ctx.dataHora.integratedScheduleId = scheduleId;
ctx.step = 'CRIAR_AGENDA';
flow.set(contextKey, ctx);

msg.integratedScheduleId = scheduleId;
msg.establishmentCode = String(ctx.configuracoes.establishmentId || msg.establishmentCode || 1);
msg.buscarHorarios = true;
msg.retryHorariosCount = 0;
msg.reply = { type: 'text', text: 'Buscando horários disponíveis...' };
return msg;

/**
 * DOC-FLOW: Processar Horários
 * O que faz: Agrupa e organiza horários por dia com pagina\u00e7\u00e3o.
 * Para que serve: Facilitar a escolha de dia e horário pelo usuário.
 */
const ctx = msg.ctx || {};
const contextKey = msg.contextKey;

const parseMaybeJson = (v) => {
  if (typeof v !== 'string') return v;
  const t = v.trim();
  if (!t) return v;
  if ((t.startsWith('{') && t.endsWith('}')) || (t.startsWith('[') && t.endsWith(']'))) {
    try { return JSON.parse(t); } catch (e) { return v; }
  }
  return v;
};

const pickResults = (raw) => {
  const r = parseMaybeJson(raw);
  if (Array.isArray(r)) return r;
  if (!r || typeof r !== 'object') return [];
  if (Array.isArray(r.results)) return r.results;
  if (Array.isArray(r.data)) return r.data;
  if (r.data && Array.isArray(r.data.results)) return r.data.results;
  if (r.result && Array.isArray(r.result.results)) return r.result.results;
  if (Array.isArray(r.items)) return r.items;
  return [];
};

const extractDateKey = (value) => {
  const raw = String(value || '').trim();
  if (!raw) return '';
  const direct = raw.match(/^(\d{4}-\d{2}-\d{2})/);
  if (direct) return direct[1];
  const parsed = Date.parse(raw);
  if (Number.isNaN(parsed)) return '';
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: 'America/Sao_Paulo',
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  }).formatToParts(new Date(parsed));
  const y = parts.find(p => p.type === 'year')?.value;
  const m = parts.find(p => p.type === 'month')?.value;
  const d = parts.find(p => p.type === 'day')?.value;
  return (y && m && d) ? (y + '-' + m + '-' + d) : '';
};

if (msg.statusCode && (msg.statusCode < 200 || msg.statusCode >= 300)) {
  node.error('Erro HTTP ' + msg.statusCode + ' ao consultar horários', msg);
  return msg;
}

const results = pickResults(msg.payload);
const retryCount = Number(msg.retryHorariosCount || 0);

if (!results || results.length === 0) {
  if (retryCount < 2 && msg.integratedScheduleId) {
    const retryMsg = Object.assign({}, msg, {
      retryHorariosCount: retryCount + 1,
      buscarHorarios: true,
      reply: undefined
    });
    setTimeout(() => node.send([null, retryMsg]), 1200);
    return null;
  }

  ctx.dataHora = ctx.dataHora || {};
  ctx.dataHora.todosHorariosPorDia = null;
  ctx.dataHora.diasDisponiveis = null;
  ctx.dataHora.horariosDisponiveis = null;
  ctx.dataHora.horarioSelecionado = null;
  ctx.dataHora.diaEscolhido = null;
  ctx.dataHora.paginaHorariosAtual = 0;
  ctx.step = 'MENU_PRINCIPAL';
  ctx.updatedAt = msg.now;
  flow.set(contextKey, ctx);

  msg.reply = {
    type: 'list',
    text: 'Nenhum horário disponível no momento para esta seleção.\n\n*Menu Principal*\n\nEscolha uma opção:',
    buttonText: 'Ver opções',
    sections: [{ title: 'Opções', rows: [
      { id: 'MENU_AGENDAR', title: 'Agendar Consulta' },
      { id: 'MENU_AGENDAR_EXAME', title: 'Agendar Exame' },
      { id: 'MENU_MEUS_AGENDAMENTOS', title: 'Meus agendamentos' },
      { id: 'MENU_SAIR', title: 'Sair' }
    ] }]
  };
  return msg;
}

const horariosPorDia = new Map();

results.forEach(result => {
  const scheduleDate = result.scheduleDate || result.date || result.startDate || '';
  const firstItem = (result.integratedScheduleItems || result.items || [])[0] || {};
  const scheduleSuggestion = (firstItem.scheduleSuggestions || result.scheduleSuggestions || [])[0] || {};
  const horaBase = firstItem.startTime || scheduleSuggestion.startTime || scheduleDate;
  const dataKey = extractDateKey(horaBase || scheduleDate);
  if (!dataKey) return;

  const valor = Number(scheduleSuggestion.itemValue || result.totalValue || 0);
  if (!horariosPorDia.has(dataKey)) horariosPorDia.set(dataKey, []);
  horariosPorDia.get(dataKey).push({
    suggestionId: result.suggestionId || scheduleSuggestion.suggestionId,
    data: horaBase || scheduleDate,
    hora: horaBase,
    integratedScheduleItemId: firstItem.integratedScheduleItemId,
    integratedScheduleId: scheduleSuggestion.integratedScheduleId || msg.integratedScheduleId,
    scheduleCode: scheduleSuggestion.scheduleCode,
    physicianCode: scheduleSuggestion.physicianCode || null,
    valor: Number.isFinite(valor) ? valor : 0
  });
});

const diasOrdenados = Array.from(horariosPorDia.entries()).sort((a, b) => new Date(a[0]) - new Date(b[0]));
ctx.dataHora = ctx.dataHora || {};
ctx.dataHora.todosHorariosPorDia = Object.fromEntries(diasOrdenados);
