const flatten = (input) => {
  const out = [];
  const stack = [input];
  const seen = new Set();
  while (stack.length) {
    const cur = stack.pop();
    if (!cur || typeof cur !== 'object') continue;
    if (seen.has(cur)) continue;
    seen.add(cur);
    out.push(cur);
    if (Array.isArray(cur)) {
      for (const it of cur) stack.push(it);
      continue;
    }
    for (const k of Object.keys(cur)) {
      const v = cur[k];
      if (v && typeof v === 'object') stack.push(v);
    }
  }
  return out;
};

